/* Auto-generated resource icons (base64 PNG) */
'use strict';

const RESOURCE_ICONS = {
  bonds: "data:image/png;base64,",
  gold: "data:image/png;base64,",
  silver: "data:image/png;base64,",
};

/**
 * Парсим строку ресурса: убираем пробелы, возвращаем число или null
 */
function parseResource(val) {
  if (val === null || val === undefined || String(val).trim() === '') return null;
  const n = parseInt(String(val).replace(/\s+/g, ''), 10);
  return isNaN(n) ? null : n;
}

/**
 * Полное число с пробелами-разделителями: 12945 → "12 945"
 */
function formatResourceFull(n) {
  return n.toLocaleString('ru-RU');
}

/**
 * Сокращённый формат (всегда в меньшую сторону):
 * 12945 → "12.9К", 4560 → "4.5К", 8568930 → "8.5 млн"
 */
function formatResourceShort(n) {
  if (n >= 1_000_000) {
    const val = Math.floor(n / 100_000) / 10;
    return val % 1 === 0 ? val + 'М' : val.toFixed(1) + 'М';
  }
  if (n >= 1_000) {
    const val = Math.floor(n / 100) / 10;
    return val % 1 === 0 ? val + 'К' : val.toFixed(1) + 'К';
  }
  return String(n);
}

/**
 * Рендерит блок с иконками ресурсов.
 * mode: 'full' — полное число (десктоп таблица)
 *        'short' — сокращённое (мобайл таблица и большие карточки)
 * Возвращает HTML-строку.
 */
function renderResourceIcons(resources, mode) {
  if (!resources) return '';
  const order = [
    { key: 'bonds',  icon: RESOURCE_ICONS.bonds,  label: 'Боны',    mod: 'bonds'  },
    { key: 'gold',   icon: RESOURCE_ICONS.gold,   label: 'Золото',  mod: 'gold'   },
    { key: 'silver', icon: RESOURCE_ICONS.silver, label: 'Серебро', mod: 'silver' },
  ];
  const items = order
    .map(({ key, icon, label, mod }) => {
      const n = parseResource(resources[key]);
      if (n === null) return '';
      const displayVal = mode === 'full' ? formatResourceFull(n) : formatResourceShort(n);
      return `<span class="resource-item">` +
        `<img src="${icon}" alt="${label}" class="resource-icon-img resource-icon-img--${mod}">` +
        `<span class="resource-value">${displayVal}</span>` +
        `</span>`;
    })
    .filter(Boolean);
  if (items.length === 0) return '';
  return `<div class="resource-icons">${items.join('')}</div>`;
}
